def dieSimulator(n, rollMax):
    MOD = 10**9 + 7
    # dp[face][consec] = ways
    dp = [[0]*16 for _ in range(6)]
    for f in range(6): dp[f][1] = 1
    for _ in range(n - 1):
        ndp = [[0]*16 for _ in range(6)]
        for f in range(6):
            for c in range(1, rollMax[f] + 1):
                if not dp[f][c]: continue
                for nf in range(6):
                    if nf == f:
                        if c + 1 <= rollMax[nf]: ndp[nf][c+1] = (ndp[nf][c+1] + dp[f][c]) % MOD
                    else:
                        ndp[nf][1] = (ndp[nf][1] + dp[f][c]) % MOD
        dp = ndp
    return sum(dp[f][c] for f in range(6) for c in range(1, 16)) % MOD

